      { name: "Cilantro Chilli Chicken", price: "₹349" },
      { name: "Chicken Wings", price: "₹349" },
      { name: "Tangra Style Chilli Chicken", price: "₹399" },
      { name: "Chicken Yakitori", price: "₹449" },
      { name: "Steamed Fish", price: "₹449" },
      { name: "Kung Pao Chicken", price: "₹499" },
      { name: "Golden Fried Prawn", price: "₹499" },
      { name: "Butter Chilli Garlic Prawns", price: "₹499" },
      { name: "Pan Fried Chilli Fish", price: "₹599" },
      { name: "Honey Soya Pork Belly", price: "₹599" },
    ]
  },
  {
    id: "starters",
    name: "Starters",
    icon: Flame,
    items: [
      { name: "Crispy Calamari", description: "Golden fried squid rings with garlic aioli", price: "₹495" },
      { name: "Chicken Wings", description: "Buffalo style with blue cheese dip", price: "₹445" },
      { name: "Loaded Nachos", description: "Cheese, jalapeños, salsa, sour cream", price: "₹395" },
      { name: "Paneer Tikka", description: "Tandoori spiced cottage cheese skewers", price: "₹375" },
      { name: "Fish Fingers", description: "Beer battered with tartar sauce", price: "₹475" },
      { name: "Mushroom Bruschetta", description: "Garlic toast with sautéed mushrooms", price: "₹325" },
    ]
  },
  {
    id: "mains",
    name: "Main Course",
    icon: UtensilsCrossed,
    items: [
      { name: "Grilled Chicken Steak", description: "With herb butter and mashed potatoes", price: "₹695" },
      { name: "Fish & Chips", description: "Beer battered fish with crispy fries", price: "₹595" },
      { name: "Butter Chicken", description: "Creamy tomato gravy with naan", price: "₹545" },
      { name: "Lamb Chops", description: "Rosemary grilled with mint chutney", price: "₹895" },
      { name: "Penne Arrabiata", description: "Spicy tomato sauce with parmesan", price: "₹445" },
      { name: "Thai Green Curry", description: "Vegetables in coconut curry with rice", price: "₹475" },
    ]
